script:
(function (root_element) {
  const root = root_element.querySelector("#fbr_fiscal_year_kpi_block");
  if (!root) return;
  const $ = (selector) => root.querySelector(selector);
  const chartCanvas = $("#fbr_kpi_sales_purchase_chart");
  let lastData = null;
  let chartInstance = null;
  let chartLibPromise = null;

  function money(value) {
    return Math.round(Number(value || 0)).toLocaleString();
  }

  function num(value) {
    return Math.round(Number(value || 0)).toLocaleString();
  }

  function setText(selector, value) {
    const element = $(selector);
    if (element) element.textContent = value;
  }

  function setChange(selector, value) {
    const element = $(selector);
    if (!element) return;
    const numeric = Number(value || 0);
    element.textContent = `${numeric >= 0 ? "+" : ""}${numeric.toFixed(1)}%`;
    element.classList.toggle("bad", numeric < 0);
  }

  function loadChartLibs() {
    if (chartLibPromise) return chartLibPromise;
    chartLibPromise = new Promise(function (resolve) {
      if (window.Chart) return resolve();
      const script = document.createElement("script");
      script.src = "https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js";
      script.onload = function () { resolve(); };
      script.onerror = function () { resolve(); };
      document.head.appendChild(script);
    });
    return chartLibPromise;
  }

  const valueLabelPlugin = {
    id: "fbrKpiValueLabels",
    afterDatasetsDraw(chart) {
      const ctx = chart.ctx;
      const chartArea = chart.chartArea;
      ctx.save();
      ctx.font = "700 10px Segoe UI, sans-serif";
      ctx.fillStyle = "#111827";
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      chart.data.datasets.forEach(function (dataset, datasetIndex) {
        if (!chart.isDatasetVisible(datasetIndex)) return;
        const meta = chart.getDatasetMeta(datasetIndex);
        meta.data.forEach(function (bar, index) {
          const value = Number(dataset.data[index] || 0);
          if (!value) return;
          const label = Math.round(value).toLocaleString();
          const props = bar.getProps(["x", "y", "base"], true);
          const barHeight = Math.abs(props.base - props.y);
          let y = barHeight > 72 ? props.y + Math.min(30, barHeight / 2) : props.y - 10;
          y = Math.max(chartArea.top + 24, Math.min(chartArea.bottom - 24, y));
          ctx.save();
          ctx.translate(props.x, y);
          ctx.rotate(-Math.PI / 2);
          ctx.fillText(label, 0, 0);
          ctx.restore();
        });
      });
      ctx.restore();
    },
  };

  function drawBarChart(canvas, labels, sales, purchases) {
    if (!canvas) return;
    loadChartLibs().then(function () {
      if (!window.Chart) return;
      if (chartInstance) {
        try { chartInstance.destroy(); } catch (e) {}
        chartInstance = null;
      }
      chartInstance = new Chart(canvas.getContext("2d"), {
        type: "bar",
        data: {
          labels: labels || [],
          datasets: [
            {
              label: "Sales",
              data: sales || [],
              backgroundColor: "#2da9e1",
              borderColor: "#2da9e1",
              borderWidth: 0,
              borderRadius: 0,
              maxBarThickness: 42,
            },
            {
              label: "Purchases",
              data: purchases || [],
              backgroundColor: "#47c878",
              borderColor: "#47c878",
              borderWidth: 0,
              borderRadius: 0,
              maxBarThickness: 42,
            },
          ],
        },
        plugins: [valueLabelPlugin],
        options: {
          responsive: true,
          maintainAspectRatio: false,
          layout: { padding: { top: 18, right: 8, bottom: 0, left: 0 } },
          plugins: {
            legend: {
              display: true,
              position: "top",
              align: "start",
              labels: {
                boxWidth: 12,
                boxHeight: 12,
                color: "#334155",
                font: { size: 11, weight: "700" },
              },
            },
            tooltip: {
              callbacks: {
                label: function (context) {
                  return `${context.dataset.label}: ${Math.round(Number(context.raw || 0)).toLocaleString()}`;
                },
              },
            },
          },
          scales: {
            x: {
              grid: { display: false },
              ticks: { maxRotation: 0, autoSkip: true, color: "#334155", font: { size: 10 } },
            },
            y: {
              beginAtZero: true,
              grid: { color: "#eef2f7" },
              ticks: {
                color: "#334155",
                font: { size: 10 },
                callback: function (value) { return Math.round(Number(value || 0)).toLocaleString(); },
              },
            },
          },
        },
      });
    });
  }

  function render(data) {
    lastData = data;
    const summary = data.summary || {};
    const sales = data.sales || {};
    const purchases = data.purchases || {};
    setText("#fbr_kpi_period", `${data.company || ""} · ${data.period_label || "Last fiscal year"}`);
    setText("#fbr_kpi_sales_exclusive", money(sales.exclusive));
    setText("#fbr_kpi_sales_exclusive_line", money(sales.exclusive));
    setText("#fbr_kpi_sales_tax", money(sales.tax));
    setText("#fbr_kpi_sales_inclusive", money(sales.inclusive));
    setText("#fbr_kpi_expenses", money(summary.expenses));
    setText("#fbr_kpi_direct_expenses", money(summary.direct_expenses));
    setText("#fbr_kpi_indirect_expenses", money(summary.indirect_expenses));
    setText("#fbr_kpi_direct_expenses_pct", `${Number(summary.direct_expenses_pct || 0).toFixed(1)}%`);
    setText("#fbr_kpi_indirect_expenses_pct", `${Number(summary.indirect_expenses_pct || 0).toFixed(1)}%`);
    setText("#fbr_kpi_profit", money(summary.profit));
    setText("#fbr_kpi_margin", `${Number(summary.margin || 0).toFixed(1)}%`);
    setText("#fbr_kpi_sales_count", num(sales.invoice_count));
    setText("#fbr_kpi_submitted", num(sales.submitted_count));
    setText("#fbr_kpi_draft", num(sales.draft_count));
    setText("#fbr_kpi_returns", num(sales.return_count));
    setText("#fbr_kpi_fbr_success", num(sales.fbr_success_count));
    setText("#fbr_kpi_fbr_success_line", num(sales.fbr_success_count));
    setText("#fbr_kpi_fbr_pending", num(sales.fbr_pending_count));
    setText("#fbr_kpi_purchase_count", num(purchases.purchase_count));
    setText("#fbr_kpi_purchase_total", money(purchases.purchase_total));
    setChange("#fbr_kpi_revenue_change", summary.revenue_change);
    setChange("#fbr_kpi_expenses_change", summary.expenses_change);
    setChange("#fbr_kpi_profit_change", summary.profit_change);
    setChange("#fbr_kpi_margin_change", summary.margin_change);
    const trend = data.trend || {};
    drawBarChart(chartCanvas, trend.labels || [], trend.sales || [], trend.purchases || []);
  }

  frappe.call({
    method: "fbr_integration.custom_dashboard_api.fiscal_year_kpi_block_data",
    callback: function (r) {
      render(r.message || {});
    },
    error: function () {
      root.innerHTML = '<div class="fbr-kpi-empty">Unable to load fiscal year summary.</div>';
    },
  });

  window.addEventListener("resize", frappe.utils.debounce(function () {
    if (lastData) render(lastData);
  }, 300));
})(root_element);
